const body = $json.body || $json;
const payload = body.payload || {};
const signal = payload.signal || payload;
const trade = payload.trade || {};
const eventType = body.event_type || 'platform.event';
const chatId = body.chat_id || payload.chatId || null;

function clean(v) { return String(v ?? '').replace(/<[^>]*>/g, '').trim(); }

if (eventType === 'signal.created' || payload.silent) {
  return [{ json: { skipTelegram: true, eventType } }];
}

let text;
if (eventType === 'trade.activated' || eventType === 'trade.opened') {
  text = payload.message || body.message || `Trade opened: ${clean(signal.symbol || trade.symbol)}`;
} else if (eventType === 'trade.closed') {
  const pnl = trade.pnl ?? payload.pnl ?? 0;
  const emoji = pnl >= 0 ? '🟢' : '🔴';
  text = `${emoji} <b>Trade Closed</b>\n\n${clean(trade.symbol)} ${clean(trade.direction)}\n${clean(payload.message || body.message)}\nPnL: <b>${pnl >= 0 ? '+' : ''}${Number(pnl).toFixed(2)} USDT</b>`;
} else if (eventType === 'trade.update') {
  text = `📈 <b>Trade Update</b>\n\n${clean(trade.symbol)}\n${clean(payload.message || body.message)}\nPnL: ${trade.pnl == null ? 'Open' : trade.pnl + ' USDT'}`;
} else if (eventType === 'wallet.consensus') {
  const s = payload.signal || {};
  text = `🐋 <b>Smart Wallet Consensus</b>\n\nToken: ${clean(s.symbol)}\nWallets: ${clean(s.wallet_count)}\nConfidence: ${clean(s.confidence)}/100`;
} else {
  text = `🔔 <b>${clean(eventType)}</b>\n\n${clean(payload.message || body.message || '')}`;
}

return [{ json: { text, eventType, chatId, skipTelegram: false } }];

const update = $json;
const message = update.message || update.callback_query?.message || {};
const chatId = message.chat?.id || update.callback_query?.from?.id;
const rawText = update.message?.text || update.callback_query?.data || '';
const text = String(rawText).trim();
const parts = text.split(/\s+/);
const cmd = parts[0]?.toLowerCase() || '';

let method = 'POST';
let path = '/api/telegram/callback';
let body = {};
let label = 'Trade';
let skipHttp = false;

const cb = update.callback_query;
if (cb?.data && /^(execute|default|manual|size|skip):/.test(cb.data)) {
  body = { callback_data: cb.data, chat_id: chatId };
  return [{ json: { chatId, method, path, body, label, skipHttp: false } }];
}

if (!cb && /^[\d.]+(\s*(usdt|usd)?)?$/i.test(text)) {
  body = { action: 'text_size', chat_id: chatId, text };
  return [{ json: { chatId, method, path, body, label: 'Manual size', skipHttp: false } }];
}

path = '/api/ai/query';
body = { question: text, chatId };
label = 'AI answer';

if (cmd === '/stats') { method = 'GET'; path = '/api/scanner/status'; body = undefined; label = 'Scanner'; }
else if (cmd === '/demo') { path = '/api/control/demo-signal'; body = { symbol: (parts[1]||'BTCUSDT').toUpperCase(), force: true }; label = 'Demo signal'; }
else if (cmd === '/stop') { path = '/api/scanner/stop'; body = { source: 'telegram' }; label = 'Scanner stopped'; }
else if (cmd === '/start') {
  return [{ json: { chatId, skipHttp: true, label: 'Help', reply: '🤖 Tap signal buttons: SHORT/LONG → Default or Manual size.\n/stats /demo /stop' } }];
}

return [{ json: { chatId, method, path, body, label, skipHttp } }];

const cmd = $('Parse Telegram Command').item.json;
const data = $json;
if (data.answer) {
  return [{ json: { chatId: cmd.chatId, text: data.answer, skipReply: false } }];
}
if (data.ok && data.message) {
  return [{ json: { chatId: cmd.chatId, text: data.message, skipReply: false } }];
}
if (data.ok && !data.message) {
  return [{ json: { chatId: cmd.chatId, skipReply: true } }];
}
const failed = data.executed === false || data.error || data.reason;
let detail = data.message || data.error || data.reason || JSON.stringify(data, null, 2);
if (detail.length > 3200) detail = detail.slice(0, 3200);
const icon = failed ? '❌' : '✅';
return [{ json: { chatId: cmd.chatId, text: failed ? `${icon} ${detail}` : detail, skipReply: false } }];
